let raw = items[0].json.output;

try {
  const parsed = JSON.parse(raw);
  return [{ json: parsed }];
} catch (e) {
  return [{
    json: {
      error: "Invalid JSON from AI",
      rawOutput: raw
    }
  }];
}

const seen = new Set();

const gold = $items("Fetch Gold Prices");
const equity = items;

// Get date parameters
const params = $("Set Analysis Parameters").first().json;
const startDate = new Date(params.startDate);
const endDate = new Date(params.endDate);

const combined = [];

for (let i = 0; i < equity.length; i++) {
  if (!gold[i]?.json?.Price || !equity[i]?.json?.Price) continue;

  const cleanDate = gold[i].json.Date.replace(",", "").trim();
  const currentDate = new Date(cleanDate);

  if (seen.has(cleanDate)) continue;
  seen.add(cleanDate);

  if (currentDate < startDate || currentDate > endDate) continue;

  combined.push({
    json: {
      date: cleanDate,
      goldPrice: Number(gold[i].json.Price),
      equityPrice: Number(equity[i].json.Price)
    }
  });
}

// Important safeguard
if (combined.length === 0) {
  return [{
    json: {
      error: "No market data found in selected date range"
    }
  }];
}

return combined;

if (!items.length || items[0].json.error) {
  return [
    {
      json: {
        error: items[0]?.json?.error || "No data available for selected date range"
      }
    }
  ];
}

const first = items[0].json;
const last = items[items.length - 1].json;

// Calculate returns
const goldReturn =
  ((last.goldPrice - first.goldPrice) / first.goldPrice) * 100;

const equityReturn =
  ((last.equityPrice - first.equityPrice) / first.equityPrice) * 100;

// Difference
const diff = goldReturn - equityReturn;

// Decide winner
let winner = "Equal";
if (diff > 0) winner = "Gold";
else if (diff < 0) winner = "Equity";

return [
  {
    json: {
      startDate: first.date,
      endDate: last.date,
      goldReturn: goldReturn.toFixed(2),
      equityReturn: equityReturn.toFixed(2),
      difference: diff.toFixed(2),
      winner
    }
  }
];

