parameters.jsCode:
if (!items.length || items[0].json.error) {
  return [
    {
      json: {
        chartUrl: "",
        error: items[0]?.json?.error || "No chart data available"
      }
    }
  ];
}

const labels = items.map(i => i.json.date);
const gold = items.map(i => i.json.goldPrice);
const equity = items.map(i => i.json.equityPrice);

const chartConfig = {
  type: "line",
  data: {
    labels,
    datasets: [
      {
        label: "Gold",
        data: gold,
        borderColor: "#D4AF37",
        backgroundColor: "rgba(212,175,55,0.15)",
        borderWidth: 3,
        fill: true,
        tension: 0.45
      },
      {
        label: "Equity",
        data: equity,
        borderColor: "#2E86DE",
        backgroundColor: "rgba(46,134,222,0.15)",
        borderWidth: 3,
        fill: true,
        tension: 0.45
      }
    ]
  }
};

const chartUrl =
  "https://quickchart.io/chart?width=900&height=450&backgroundColor=white&c=" +
  encodeURIComponent(JSON.stringify(chartConfig));

return [
  {
    json: {
      labels,
      gold,
      equity,
      chartUrl
    }
  }
];
